import React, { useEffect, useState, useContext } from "react";
import axios from "axios";
import { AuthContext } from "../../context/AuthContext";

const API = "http://localhost:5000/api/notifications";

const AdminNotifications = () => {
  const { user } = useContext(AuthContext);
  const [notis, setNotis] = useState([]);

  useEffect(() => {
    fetchNotifications();
  }, []);

  const fetchNotifications = async () => {
    const res = await axios.get(API, {
      headers: { Authorization: `Bearer ${user.token}` },
    });
    setNotis(res.data.data);
  };

  const markRead = async (id) => {
    await axios.put(`${API}/${id}/read`, {}, {
      headers: { Authorization: `Bearer ${user.token}` },
    });
    fetchNotifications();
  };

  return (
    <div>
      <h2 className="text-xl font-semibold text-[#4b2c35] mb-4">
        🔔 Thông báo
      </h2>

      {notis.length === 0 && (
        <p className="text-gray-500">Không có thông báo nào.</p>
      )}

      <div className="space-y-4">
        {notis.map((n) => (
          <div
            key={n._id}
            className={`p-4 rounded-lg border shadow-sm ${
              n.read ? "bg-gray-50" : "bg-pink-50 border-pink-200"
            }`}
          >
            <p className="font-medium text-[#4b2c35]">{n.message}</p>

            <p className="text-xs text-gray-500 mt-1">
              {new Date(n.createdAt).toLocaleString("vi-VN")}
            </p>

            {!n.read && (
              <button
                onClick={() => markRead(n._id)}
                className="mt-2 text-sm bg-pink-600 text-white px-3 py-1 rounded-full hover:bg-pink-700"
              >
                Đánh dấu đã đọc
              </button>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default AdminNotifications;
